package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package controllers.amateur;

import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.layout.HBox;

import java.util.function.Consumer;

public class MiniAudioPlayerController {

    @FXML
    private HBox playerBar;

    @FXML
    private Button togglePlayButton;

    private Consumer<String> navigationHandler;
    private boolean playing;

    @FXML
    public void initialize() {
        playerBar.setVisible(false);
        playerBar.setManaged(false);
    }

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setVisibleForRoute(String route) {
        boolean isMusicPage = "musique".equals(route);
        playerBar.setVisible(!isMusicPage);
        playerBar.setManaged(!isMusicPage);
    }

    @FXML
    private void onTogglePlay() {
        playing = !playing;
        togglePlayButton.setText(playing ? "||" : ">");
    }

    @FXML
    private void onPrevTrack() {
        // Placeholder for queue previous action.
    }

    @FXML
    private void onNextTrack() {
        // Placeholder for queue next action.
    }

    @FXML
    private void onOpenMusic() {
        if (navigationHandler != null) {
            navigationHandler.accept("musique");
        }
    }
}

package entities;

import java.time.LocalDate;
import java.time.LocalDateTime;

public class Personne {
    private Integer id;
    private String photoProfil;
    private String resetToken;
    private LocalDateTime resetTokenExpires;
    private String nom;
    private String prenom;
    private LocalDate dateNaissance;
    private String email;
    private String mdp;
    private String role;
    private String statut;
    private LocalDate dateInscription;
    private String numTel;
    private String ville;
    private String biographie;
    private String specialite;
    private String centreInteret;
    private String photoReferencePath;

    // Legacy field kept for compatibility with existing ServicePersonne.
    private Integer age;

    public Personne() {
    }

    public Personne(String nom, String prenom, Integer age) {
        this.nom = nom;
        this.prenom = prenom;
        this.age = age;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getPhotoProfil() {
        return photoProfil;
    }

    public void setPhotoProfil(String photoProfil) {
        this.photoProfil = photoProfil;
    }

    public String getResetToken() {
        return resetToken;
    }

    public void setResetToken(String resetToken) {
        this.resetToken = resetToken;
    }

    public LocalDateTime getResetTokenExpires() {
        return resetTokenExpires;
    }

    public void setResetTokenExpires(LocalDateTime resetTokenExpires) {
        this.resetTokenExpires = resetTokenExpires;
    }

    public String getNom() {
        return nom;
    }

    public void setNom(String nom) {
        this.nom = nom;
    }

    public String getPrenom() {
        return prenom;
    }

    public void setPrenom(String prenom) {
        this.prenom = prenom;
    }

    public LocalDate getDateNaissance() {
        return dateNaissance;
    }

    public void setDateNaissance(LocalDate dateNaissance) {
        this.dateNaissance = dateNaissance;
    }

    public String getEmail() {
        return email;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public String getMdp() {
        return mdp;
    }

    public void setMdp(String mdp) {
        this.mdp = mdp;
    }

    public String getRole() {
        return role;
    }

    public void setRole(String role) {
        this.role = role;
    }

    public String getStatut() {
        return statut;
    }

    public void setStatut(String statut) {
        this.statut = statut;
    }

    public LocalDate getDateInscription() {
        return dateInscription;
    }

    public void setDateInscription(LocalDate dateInscription) {
        this.dateInscription = dateInscription;
    }

    public String getNumTel() {
        return numTel;
    }

    public void setNumTel(String numTel) {
        this.numTel = numTel;
    }

    public String getVille() {
        return ville;
    }

    public void setVille(String ville) {
        this.ville = ville;
    }

    public String getBiographie() {
        return biographie;
    }

    public void setBiographie(String biographie) {
        this.biographie = biographie;
    }

    public String getSpecialite() {
        return specialite;
    }

    public void setSpecialite(String specialite) {
        this.specialite = specialite;
    }

    public String getCentreInteret() {
        return centreInteret;
    }

    public void setCentreInteret(String centreInteret) {
        this.centreInteret = centreInteret;
    }

    public String getPhotoReferencePath() {
        return photoReferencePath;
    }

    public void setPhotoReferencePath(String photoReferencePath) {
        this.photoReferencePath = photoReferencePath;
    }

    public Integer getAge() {
        return age;
    }

    public void setAge(Integer age) {
        this.age = age;
    }

    @Override
    public String toString() {
        return "Personne{" +
                "id=" + id +
                ", nom='" + nom + '\'' +
                ", prenom='" + prenom + '\'' +
                ", email='" + email + '\'' +
                ", role='" + role + '\'' +
                ", statut='" + statut + '\'' +
                '}';
    }
}

/* Base */
.auth-root {
	-fx-font-family: "Segoe UI", "Inter", "Arial";
	-fx-background-color: linear-gradient(to bottom right, #eef3ff 0%, #f7f9ff 45%, #eef2fb 100%);
}

.auth-landing-shell,
.auth-signup-shell {
	-fx-padding: 24;
}

.auth-card,
.auth-landing-card {
	-fx-background-color: rgba(255, 255, 255, 0.92);
	-fx-background-radius: 24;
	-fx-border-radius: 24;
	-fx-effect: dropshadow(gaussian, rgba(30, 41, 59, 0.15), 26, 0.18, 0, 12);
}

/* Top bar */
.auth-topbar {
	-fx-background-color: rgba(255, 255, 255, 0.88);
	-fx-border-color: rgba(99, 102, 241, 0.12);
	-fx-border-width: 0 0 1 0;
}

.auth-brand-mini,
.auth-brand {
	-fx-text-fill: #243b7a;
	-fx-font-weight: 800;
}

.auth-brand-mini {
	-fx-font-size: 19px;
}

.auth-topbar-link,
.auth-topbar-ghost,
.auth-topbar-primary {
	-fx-background-radius: 999;
	-fx-padding: 8 14;
	-fx-font-weight: 700;
	-fx-cursor: hand;
}

.auth-topbar-link {
	-fx-background-color: transparent;
	-fx-text-fill: #334155;
}

.auth-topbar-ghost {
	-fx-background-color: transparent;
	-fx-text-fill: #4f46e5;
	-fx-border-color: #c7d2fe;
	-fx-border-radius: 999;
	-fx-border-width: 1;
}

.auth-topbar-primary,
.auth-primary-button {
	-fx-background-color: linear-gradient(to right, #4338ca, #4f46e5);
	-fx-text-fill: white;
	-fx-background-radius: 14;
	-fx-font-weight: 700;
	-fx-cursor: hand;
}

.auth-topbar-primary:hover,
.auth-primary-button:hover {
	-fx-background-color: linear-gradient(to right, #3f37b8, #4338ca);
}

/* Landing hero */
.auth-landing-card {
	-fx-max-width: 1100;
}

.auth-landing-hero,
.auth-signup-hero {
	-fx-background-color: linear-gradient(to bottom right, #273c95 0%, #5164d9 60%, #7382ff 100%);
	-fx-background-radius: 24 0 0 24;
}

.auth-landing-panel,
.auth-signup-card {
	-fx-background-radius: 0 24 24 0;
}

.auth-hero-title,
.auth-title {
	-fx-text-fill: #ffffff;
	-fx-font-size: 32px;
	-fx-font-weight: 800;
	-fx-line-spacing: 0.2em;
}

.auth-hero-text,
.auth-subtitle,
.auth-panel-text,
.auth-helper-text,
.auth-message {
	-fx-font-size: 13px;
	-fx-line-spacing: 0.5em;
}

.auth-hero-text,
.auth-panel-text,
.auth-helper-text {
	-fx-text-fill: #667085;
}

.auth-panel-kicker,
.auth-section-title {
	-fx-text-fill: #4f46e5;
	-fx-font-size: 13px;
	-fx-font-weight: 800;
}

.auth-panel-title,
.auth-title {
	-fx-text-fill: #111827;
}

.auth-chip-row {
	-fx-padding: 2 0 0 0;
}

.auth-chip {
	-fx-background-color: rgba(255, 255, 255, 0.18);
	-fx-text-fill: #ffffff;
	-fx-background-radius: 999;
	-fx-padding: 7 14;
	-fx-font-size: 12px;
	-fx-font-weight: 700;
}

/* Form */
.auth-stepper {
	-fx-padding: 2 0 4 0;
}

.auth-step-badge {
	-fx-min-width: 34;
	-fx-min-height: 34;
	-fx-alignment: center;
	-fx-background-color: #e5e7eb;
	-fx-text-fill: #6b7280;
	-fx-font-weight: 800;
	-fx-background-radius: 999;
}

.auth-step-badge.active {
	-fx-background-color: #4f46e5;
	-fx-text-fill: white;
}

.auth-step-badge.done {
	-fx-background-color: #22c55e;
	-fx-text-fill: white;
}

.auth-field-label {
	-fx-text-fill: #334155;
	-fx-font-size: 13px;
	-fx-font-weight: 700;
}

.auth-input {
	-fx-background-color: white;
	-fx-background-radius: 22;
	-fx-border-radius: 22;
	-fx-border-color: #cbd5e1;
	-fx-border-width: 1;
	-fx-padding: 11 14;
	-fx-font-size: 14px;
}

.combo-box-base.auth-input {
	-fx-background-color: white;
	-fx-background-radius: 22;
	-fx-border-radius: 22;
	-fx-border-color: #cbd5e1;
	-fx-border-width: 1;
	-fx-font-size: 14px;
}

.combo-box-base.auth-input:focused {
	-fx-border-color: #4f46e5;
	-fx-effect: dropshadow(gaussian, rgba(79, 70, 229, 0.18), 14, 0.15, 0, 0);
}

.combo-box-base.auth-input > .list-cell {
	-fx-padding: 11 14;
}

.auth-input:focused {
	-fx-border-color: #4f46e5;
	-fx-effect: dropshadow(gaussian, rgba(79, 70, 229, 0.18), 14, 0.15, 0, 0);
}

.auth-textarea {
	-fx-pref-row-count: 4;
}

.auth-role-toggle,
.auth-secondary-button,
.auth-link-button {
	-fx-cursor: hand;
}

.auth-role-toggle {
	-fx-background-color: #edf2ff;
	-fx-text-fill: #334155;
	-fx-background-radius: 999;
	-fx-border-radius: 999;
	-fx-border-color: transparent;
	-fx-font-weight: 700;
	-fx-padding: 10 16;
}

.auth-role-toggle:selected {
	-fx-background-color: #4f46e5;
	-fx-text-fill: white;
}

.auth-secondary-button {
	-fx-background-color: transparent;
	-fx-text-fill: #334155;
	-fx-font-weight: 700;
	-fx-background-radius: 14;
	-fx-border-color: #c7d2fe;
	-fx-border-width: 1.2;
	-fx-border-radius: 14;
	-fx-padding: 12 18;
}

.auth-secondary-button:hover,
.auth-topbar-link:hover,
.auth-link-button:hover {
	-fx-background-color: #eef2ff;
}

.auth-link-button {
	-fx-background-color: transparent;
	-fx-text-fill: #4f46e5;
	-fx-font-weight: 700;
	-fx-padding: 0;
}

.auth-photo-preview {
	-fx-min-width: 150;
	-fx-min-height: 150;
	-fx-background-color: #cbd5e1;
	-fx-background-radius: 18;
	-fx-border-radius: 18;
	-fx-border-color: rgba(255,255,255,0.55);
	-fx-border-width: 1;
}

.auth-photo-placeholder {
	-fx-text-fill: white;
	-fx-font-weight: 700;
	-fx-opacity: 0.85;
}

.auth-message {
	-fx-min-height: 20;
}

.auth-message.error {
	-fx-text-fill: #dc2626;
}

.auth-message.success {
	-fx-text-fill: #16a34a;
}

.auth-signup-card {
	-fx-background-color: rgba(255, 255, 255, 0.96);
}

.auth-scroll,
.auth-scroll > .viewport {
	-fx-background-color: transparent;
