	-fx-background-color: transparent;
	-fx-text-fill: #334155;
	-fx-font-weight: 700;
	-fx-background-radius: 14;
	-fx-border-color: #c7d2fe;
	-fx-border-width: 1.2;
	-fx-border-radius: 14;
	-fx-padding: 12 18;
}

.auth-secondary-button:hover,
.auth-topbar-link:hover,
.auth-link-button:hover {
	-fx-background-color: #eef2ff;
}

.auth-link-button {
	-fx-background-color: transparent;
	-fx-text-fill: #4f46e5;
	-fx-font-weight: 700;
	-fx-padding: 0;
}

.auth-photo-preview {
	-fx-min-width: 150;
	-fx-min-height: 150;
	-fx-background-color: #cbd5e1;
	-fx-background-radius: 18;
	-fx-border-radius: 18;
	-fx-border-color: rgba(255,255,255,0.55);
	-fx-border-width: 1;
}

.auth-photo-placeholder {
	-fx-text-fill: white;
	-fx-font-weight: 700;
	-fx-opacity: 0.85;
}

.auth-message {
	-fx-min-height: 20;
}

.auth-message.error {
	-fx-text-fill: #dc2626;
}

.auth-message.success {
	-fx-text-fill: #16a34a;
}

.auth-signup-card {
	-fx-background-color: rgba(255, 255, 255, 0.96);
}

.auth-scroll,
.auth-scroll > .viewport {
	-fx-background-color: transparent;
}
